import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void chain() {
        // [1,2],[2,3],[3,4]: attend day 1, 2, 3
        assertEquals(3, new Solution().maxEvents(new int[][]{{1,2},{2,3},{3,4}}));
    }

    @Test
    void onlyTwoDaysAvailable() {
        // Three copies of [1,2]: only days 1 and 2 exist — attend 2
        assertEquals(2, new Solution().maxEvents(new int[][]{{1,2},{1,2},{1,2}}));
    }

    @Test
    void leetcodeExample() {
        // [[1,4],[4,4],[2,2],[3,4],[1,1]] — classical problem; answer is 4
        assertEquals(4, new Solution().maxEvents(new int[][]{{1,4},{4,4},{2,2},{3,4},{1,1}}));
    }

    @Test
    void singleEvent() {
        assertEquals(1, new Solution().maxEvents(new int[][]{{5,7}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().maxEvents(new int[][]{}));
    }

    @Test
    void disjointEvents() {
        // Completely disjoint — all 3 can be attended
        assertEquals(3, new Solution().maxEvents(new int[][]{{1,1},{3,3},{5,5}}));
    }

    @Test
    void longRangeWithContention() {
        // [1,1] must be attended day 1; [1,3] and [1,3] use days 2 and 3
        assertEquals(3, new Solution().maxEvents(new int[][]{{1,1},{1,3},{1,3}}));
    }
}
